#!/bin/bash
log(){ echo "{\"timestamp\":\"$(date -u +"%Y-%m-%dT%H:%M:%SZ")\",\"component\":\"$1\",\"target\":\"$2\",\"status\":\"$3\",\"details\":\"$4\"}" | tee -a /var/log/sentinel.log; }; CONFIG_FILE="${1:-sentinel.conf}"; [ ! -f "$CONFIG_FILE" ] && log "SYSTEM" "config" "ALERT" "Config file missing" && exit 1; source "$CONFIG_FILE"; for svc in "${SERVICES[@]}"; do if pgrep -f "$svc" >/dev/null 2>&1; then log "SERVICE" "$svc" "OK" "Service is running"; else eval "$svc" 2>/dev/null && log "SERVICE" "$svc" "FIXED" "Restarted service" || log "SERVICE" "$svc" "ALERT" "Failed to restart"; fi; done; for file in "${FILES_TO_WATCH[@]}"; do gold="/var/backups/sentinel/$(basename "$file").gold"; if [ ! -f "$gold" ]; then log "INTEGRITY" "$file" "ALERT" "No golden copy found"; elif cmp -s "$file" "$gold" 2>/dev/null; then log "INTEGRITY" "$file" "OK" "Integrity verified"; else cp "$gold" "$file" 2>/dev/null && log "INTEGRITY" "$file" "FIXED" "Restored from golden copy" || log "INTEGRITY" "$file" "ALERT" "Failed to restore"; fi; done
